  1	import * as React from 'react';
  2	import { DropdownGroup, DropdownItem, TooltipPosition } from '@patternfly/react-core';
  3	import { serverConfig } from 'config';
  4	import {
  5	  buildWorkloadInjectionPatch,
  6	  WIZARD_DISABLE_AUTO_INJECTION,
  7	  WIZARD_EDIT_ANNOTATIONS,
  8	  WIZARD_ENABLE_AUTO_INJECTION,
  9	  WIZARD_REMOVE_AUTO_INJECTION
 10	} from './WizardActions';
 11	import * as API from '../../services/Api';
 12	import * as AlertUtils from '../../utils/AlertUtils';
 13	import { Workload } from 'types/Workload';
 14	import { renderDisabledDropdownOption } from 'utils/DropdownUtils';
 15	import { MessageType } from 'types/MessageCenter';
 16	import { groupMenuStyle } from 'styles/DropdownStyles';
 17	import { t } from 'utils/I18nUtils';
 18	import { getGVKTypeString } from '../../utils/IstioConfigUtils';
 19	import { gvkType } from '../../types/IstioConfigList';
 20	
 21	type Props = {
 22	  actionsLabel: boolean;
 23	  annotations?: { [key: string]: string };
 24	  namespace: string;
 25	  onAction: (key: string) => void;
 26	  workload: Workload;
 27	};
 28	
 29	export const WorkloadWizardActionsDropdownGroup: React.FunctionComponent<Props> = (props: Props) => {
 30	  const actionItems: React.ReactNode[] = [];
 31	
 32	  const onAction = (key: string): void => {
 33	    switch (key) {
 34	      case WIZARD_ENABLE_AUTO_INJECTION:
 35	      case WIZARD_DISABLE_AUTO_INJECTION:
 36	      case WIZARD_REMOVE_AUTO_INJECTION:
 37	        const remove = key === WIZARD_REMOVE_AUTO_INJECTION;
 38	        const enable = key === WIZARD_ENABLE_AUTO_INJECTION;
 39	        const jsonInjectionPatch = buildWorkloadInjectionPatch(props.workload.gvk, enable, remove);
 40	        API.updateWorkload(
 41	          props.namespace,
 42	          props.workload.name,
 43	          props.workload.gvk,
 44	          jsonInjectionPatch,
 45	          undefined,
 46	          props.workload.cluster
 47	        )
 48	          .then(_ => {
 49	            AlertUtils.add(`Workload ${props.workload.name} updated`, 'default', MessageType.SUCCESS);
 50	          })
 51	          .catch(error => {
 52	            AlertUtils.addError(`Could not update workload ${props.workload.name}`, error);
 53	          })
 54	          .finally(() => {
 55	            props.onAction(key);
 56	          });
 57	        break;
 58	      case WIZARD_EDIT_ANNOTATIONS: {
 59	        props.onAction(key);
 60	        break;
 61	      }
 62	      default:
 63	        console.warn(`WorkloadWizardDropdown: key ${key} not supported`);
 64	    }
 65	  };
 66	
 67	  if (serverConfig.kialiFeatureFlags.istioInjectionAction && !props.workload.isAmbient) {
 68	    const enableAction = (
 69	      <DropdownItem
 70	        data-test={WIZARD_ENABLE_AUTO_INJECTION}
 71	        key={WIZARD_ENABLE_AUTO_INJECTION}
 72	        component="button"
 73	        onClick={() => onAction(WIZARD_ENABLE_AUTO_INJECTION)}
 74	        isDisabled={serverConfig.deployment.viewOnlyMode}
 75	      >
 76	        {t('Enable Auto Injection')}
 77	      </DropdownItem>
 78	    );
 79	
 80	    const enableActionWrapper = serverConfig.deployment.viewOnlyMode
 81	      ? renderDisabledDropdownOption(
 82	          'enable_auto_injection',
 83	          TooltipPosition.left,
 84	          t('User does not have permission'),
 85	          enableAction
 86	        )
 87	      : enableAction;
 88	
 89	    const disableAction = (
 90	      <DropdownItem
 91	        data-test={WIZARD_DISABLE_AUTO_INJECTION}
 92	        key={WIZARD_DISABLE_AUTO_INJECTION}
 93	        component="button"
 94	        onClick={() => onAction(WIZARD_DISABLE_AUTO_INJECTION)}
 95	        isDisabled={serverConfig.deployment.viewOnlyMode}
 96	      >
 97	        {t('Disable Auto Injection')}
 98	      </DropdownItem>
 99	    );
100	
101	    const disableActionWrapper = serverConfig.deployment.viewOnlyMode
102	      ? renderDisabledDropdownOption(
103	          'disable_auto_injection',
104	          TooltipPosition.left,
105	          t('User does not have permission'),
106	          disableAction
107	        )
108	      : disableAction;
109	
110	    const removeAction = (
111	      <DropdownItem
112	        data-test={WIZARD_REMOVE_AUTO_INJECTION}
113	        key={WIZARD_REMOVE_AUTO_INJECTION}
114	        component="button"
115	        onClick={() => onAction(WIZARD_REMOVE_AUTO_INJECTION)}
116	        isDisabled={serverConfig.deployment.viewOnlyMode}
117	      >
118	        {t('Remove Auto Injection')}
119	      </DropdownItem>
120	    );
121	
122	    const removeActionWrapper = serverConfig.deployment.viewOnlyMode
123	      ? renderDisabledDropdownOption(
124	          'remove_auto_injection',
125	          TooltipPosition.left,
126	          t('User does not have permission'),
127	          removeAction
128	        )
129	      : removeAction;
130	
131	    if (props.workload.istioInjectionAnnotation !== undefined && props.workload.istioInjectionAnnotation) {
132	      actionItems.push(disableActionWrapper);
133	      actionItems.push(removeActionWrapper);
134	    } else if (props.workload.istioInjectionAnnotation !== undefined && !props.workload.istioInjectionAnnotation) {
135	      actionItems.push(enableActionWrapper);
136	      actionItems.push(removeActionWrapper);
137	    } else {
138	      // If sidecar is present, we offer first the disable action
139	      actionItems.push(props.workload.istioSidecar ? disableActionWrapper : enableActionWrapper);
140	    }
141	  }
142	
143	  // Annotations
144	  if (props.annotations && getGVKTypeString(props.workload.gvk) === getGVKTypeString(gvkType.Deployment)) {
145	    const annotationsAction = (
146	      <DropdownItem
147	        data-test={WIZARD_EDIT_ANNOTATIONS}
148	        key={WIZARD_EDIT_ANNOTATIONS}
149	        component="button"
150	        onClick={() => onAction(WIZARD_EDIT_ANNOTATIONS)}
151	      >
152	        {serverConfig.kialiFeatureFlags.istioAnnotationAction && !serverConfig.deployment.viewOnlyMode
153	          ? t('Edit Annotations')
154	          : t('View Annotations')}
155	      </DropdownItem>
156	    );
157	
158	    actionItems.push(annotationsAction);
159	  }
160	
161	  if (props.actionsLabel && actionItems.length > 0) {
162	    return (
163	      <DropdownGroup key={`group_actions`} label={t('Actions')} className={groupMenuStyle} children={actionItems} />
164	    );
165	  } else {
166	    return <>{actionItems}</>;
167	  }
168	};

